mapper.select:

WHERE r.gym_id = #{gymId}

  AND r.status = #{status}


  AND r.reason = #{reason}


ORDER BY r.created_at DESC
LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
  FROM crm_re_registration r
  LEFT JOIN (
      SELECT user_id, MAX(end_date) AS end_date FROM membership GROUP BY user_id
  ) me ON me.user_id = r.member_id
 WHERE r.gym_id = #{gymId}

   AND r.status = #{status}


   AND r.reason = #{reason}

SELECT COUNT(*) > 0
  FROM crm_re_registration
 WHERE member_id = #{memberId}
   AND gym_id    = #{gymId}
   AND reason    = #{reason}
   AND status NOT IN ('success','failed')

SELECT COUNT(*) FROM crm_re_registration
 WHERE gym_id = #{gymId} AND status = #{status}
   AND created_at >= DATE_SUB(NOW(), INTERVAL #{days} DAY)
